@@ -79,3 +79,27 @@
     .close-button:hover, .close-button:focus {
       color: var(--text); text-decoration: none; cursor: pointer;
     }
+
+    /* Mensagens / banners */
+    .message-container { position: fixed; top: 80px; right: 20px; z-index: 1200; display: grid; gap: 8px; max-width: 360px; }
+    .msg { padding: 10px 12px; border-radius: 10px; color: #071121; font-weight: 700; box-shadow: 0 6px 18px rgba(0,0,0,0.45); }
+    .msg.info { background: linear-gradient(180deg,#a8d0ff,#7fb3ff); }
+    .msg.success { background: linear-gradient(180deg,#d1fae5,#8ee3b8); }
+    .msg.warn { background: linear-gradient(180deg,#fff4e6,#ffd8a8); }
+    .msg.error { background: linear-gradient(180deg,#ffd6d6,#ff9b9b); }
+    .msg .close { float: right; background: transparent; border: none; font-weight: 700; cursor: pointer; }
+
+    /* Chart area */
+    .chart-controls { padding: 6px 16px; }
+    .panel canvas { width: 100% !important; height: 100% !important; display: block; }
+
+    .chart-legend { display:flex; gap:12px; align-items:center; margin-top:8px; }
+    .legend-item { display:flex; gap:8px; align-items:center; padding:6px 8px; background: rgba(255,255,255,0.02); border-radius:8px; border:1px solid rgba(255,255,255,0.02); }
+    .legend-swatch { width:14px; height:14px; border-radius:4px; box-shadow: 0 2px 6px rgba(0,0,0,0.3); }
+    .legend-label { font-size:13px; color: var(--muted); }
+
+    /* Confirm modal */
+    .confirm-modal { position: fixed; inset: 0; display:flex; align-items:center; justify-content:center; z-index:1400; background: rgba(0,0,0,0.4); }
+    .confirm-modal-content { background: var(--panel); padding: 18px; border-radius: 12px; width: 420px; max-width: calc(100% - 32px); border:1px solid #223; box-shadow: 0 8px 28px rgba(0,0,0,0.5); }
+    .confirm-modal-message { color: var(--text); font-size: 15px; }
+    .confirm-modal .ghost { background: transparent; border:1px solid #333; }
